import React from 'react';

/**
 * A helper component that provides a basic accessible page structure with common landmarks.
 * This component ensures that all content passed to it is contained within appropriate
 * ARIA landmarks, addressing the Axe violation: "region".
 *
 * It includes a header, navigation, main content area, and footer.
 *
 * @param {object} props
 * @param {React.ReactNode} props.children - The main content of the page to be rendered within the main landmark.
 * @param {React.ReactNode} [props.headerContent] - Optional content for the header landmark (role="banner").
 * @param {React.ReactNode} [props.navContent] - Optional content for the navigation landmark (role="navigation").
 * @param {React.ReactNode} [props.footerContent] - Optional content for the footer landmark (role="contentinfo").
 */
const AIAccessibilityHelper = ({ children, headerContent, navContent, footerContent }) => {
  return (
    <>
      {headerContent && <header>{headerContent}</header>}
      {navContent && <nav>{navContent}</nav>}
      <main>
        {children}
      </main>
      {footerContent && <footer>{footerContent}</footer>}
    </>
  );
};

export default AIAccessibilityHelper;

